To create a Discord bot using Discord.js v14 with a slash command for banning users, follow these steps:

1. Install Discord.js v14 and create a new bot
2. Set up the bot's activities
3. Create the slash command for banning users
4. Listen for messages in the DM channel
5. Display a message when a user tries to use the slash command

Here's the code for the bot:
```javascript
const Discord = require('discord.js');
const client = new Discord.Client();
const TOKEN = 'YOUR_BOT_TOKEN';

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('message', (message) => {
  if (message.content.startsWith('!ban')) {
    const user = message.mentions.users.first();
    if (user) {
      user.ban({ days: 30 }).then(() => {
        message.reply('User banned successfully!');
      }).catch((error) => {
        console.error(`Error banning user: ${error}`);
        message.reply('Failed to ban the user. Please try again.');
      });
    } else {
      message.reply('Please mention a user to ban.');
    }
  }
});

client.login(TOKEN);
```
Replace `'YOUR_BOT_TOKEN'` with your bot's token. This code will create a basic Discord bot that listens for messages containing the slash command `'!ban'` and bans the mentioned user for 30 days if they exist.

Remember to replace the token with your own bot token, which you can get from the Developer Portal: <https://discord.com/developers/applications>.

To create a C++ function that converts a given Markdown string to HTML, you can use the Boost.Program_options library for command-line arguments and the Boost.Regex library for regular expressions. First, you need to download and install the Boost libraries from <http://www.boost.org/>.

After installing Boost, you can use the following code:
```cpp
#include <iostream>
#include <string>
#include <boost/algorithm/string.hpp>
#include <boost/regex.hpp>
#include <boost/program_options.hpp>

namespace po = boost::program_options;

int main(int argc, char** argv) {
    po::options_description desc("Allowed options");
    desc.add_options()
        ("input,i", po::value<std::string>(), "Input markdown file")
        ("output,o", po::value<std::string>(), "Output html file");
    po::positional_options_description pos_desc;
    pos_desc.add("input", -1);
    pos_desc.add("output", -1);
    po::variables options;
    po::store(po::parse_command_line(argc, argv, desc), options);
    po::notify(options);

    if (options.count("help")) {
        std::cout << desc << std::endl;
        return 0;
    }

    std::string input_file = options["input"].as<std::string>();
    std::string output_file = options["output"].as<std::string>();

    std::string markdown = read_file(input_file);
    std::string html = convert_markdown_to_html(markdown);
    write_file(html, output_file);

    std::cout << "Markdown to HTML conversion succeeded." << std::endl;
    return 0;
}

std::string read_file(const std::string& filename) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error: Unable to open file \"" << filename << "\"" << std::endl;
        return "";
    }

    std::string content((std::istreambuf_iterator<char>(file) {}, std::istreambuf_iterator<char>() {});
    file.close();
    return content;
}

std::string convert_markdown_to_html(const std::string& markdown) {
    std::string html;
    std::regex pattern("^( *)([*+-]|\\d+.[\\d]+%|\\#[\\w]+)(\\s+(.+?[*+-]\\2\\3))?(\\s+\\4)?(\\s+\\5)?$");
    std::smatch match;
    std::string replacement = "<a href=\"\\2\" style=\"text-decoration: none; color: blue;\" title=\"\\5\">\\1</a>";

    boost::replace_all(markdown, match, replacement, pattern);
    boost::replace_all(markdown, match, "<strong>\\1</strong>", pattern);
    boost::replace_all(markdown, match, "<em>\\1</em>", pattern);
    boost::replace_all(markdown, match, "<code>\\1</code>", pattern);
    boost::replace_all(markdown, match, "<abbr title=\"\\1\">\\1</abbr>", pattern);
    boost::replace_all(markdown, match, "<sup>\\2</sup>", pattern);
    boost::replace_all(markdown, match, "<sub>\\2</sub>", pattern);
    boost::replace_all(markdown, match, "<a href=\"\\2\" style=\"text-decoration: none; color: blue;\" title=\"\\3\">\\4</a>", pattern);

    html = markdown;
    return html;
}

void write_file(const std::string& content, const std::string& filename) {
    std::ofstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error: Unable to create file \"" << filename << "\"" << std::endl;
        return;
    }

    file << content;
    file.close();
}
```
To compile this code, run:
```sh
g++ -o converter converter.cpp -lboost_program_options -lboost_regex
```
This code will provide a command line interface for converting Markdown to HTML. To use it, run:
```sh
./converter -i input_file.md -o output_file.html
```
Replace `input_file.md` and `output_file.html` with the appropriate file names.

