function isPrime(num) {
  if (num <= 1) {
    return false;
  }
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) {
      return false;
    }
  }
  return true;
}

function findPrimeInArray(arr) {
  for (let i = 0; i < arr.length; i++) {
    const num = arr[i];
    if (isPrime(num)) {
      console.log(num);
      return;
    }
  }
